"use client";

import Link from "next/link";
import { cn } from "@/lib/utils";
import { useState, useEffect } from "react";

export default function Navbar() {
    const [scrolled, setScrolled] = useState(false);

    useEffect(() => {
        const handleScroll = () => setScrolled(window.scrollY > 20);
        window.addEventListener("scroll", handleScroll);
        return () => window.removeEventListener("scroll", handleScroll);
    }, []);

    return (
        <nav
            className={cn(
                "fixed top-0 w-full z-50 transition-all duration-300 px-6 py-4",
                scrolled ? "bg-white/80 backdrop-blur-md border-b border-zinc-200 py-3" : "bg-transparent"
            )}
        >
            <div className="max-w-7xl mx-auto flex justify-between items-center">
                <Link href="/" className="text-2xl font-heading font-bold tracking-tighter text-zinc-900">
                    VIBI<span className="text-blue-600">SHA.</span>
                </Link>
                <div className="hidden md:flex gap-8 items-center font-body font-medium">
                    <Link href="/" className="hover:text-blue-600 transition-colors">Home</Link>
                    <Link href="/blog" className="hover:text-blue-600 transition-colors">Blog</Link>
                    <Link href="#about" className="hover:text-blue-600 transition-colors">About</Link>
                    <Link
                        href="/blog"
                        className="bg-zinc-900 text-white px-5 py-2 rounded-full hover:bg-zinc-800 transition-all scale-100 hover:scale-105"
                    >
                        Read Blog
                    </Link>
                </div>
            </div>
        </nav>
    );
}
